@startuml
title Sistema_de_Cobranças

class Cliente {
  + id: Int
  + nome: String
  + cobranças: List<Cobrança>
  + fazerPagamento()
}

class Cobrança {
  + id: Int
  + cliente: Client
  + quitada: Boolean
  + gerarBoleto()
  + consultaBoleto(): Boolean
}

class Boleto {
  + id: Int
  + validade: Date
  + valor: Float
  + quitado: Boolean
  + foiQuitado(): Boolean
  + setQuitado(Boolean: foiQuitado)
  + informaStatusDoBoleto()
}

interface FazerCobrança {
  + gerarBoleto()
  + consultaBoleto(): Boolean
}

interface PagarBoleto {
  + fazerPagamento()
}

Cliente --|> FazerCobrança : Cobrança ..|> FazerCobrança
Cliente -- Cobrança : 1 0..*
Cobrança --|> PagarBoleto
Cobrança -- Boleto : 1 1

@enduml
